hooks.command:
node -e "
const {execSync}=require('child_process');
const ROOT='/Users/stanchito/sons-of-mountains';
try{
  // Changed files since last commit
  const changed=execSync('git -C '+ROOT+' diff --name-only HEAD 2>/dev/null && git -C '+ROOT+' diff --name-only --cached 2>/dev/null',{encoding:'utf8'}).trim().split('\n').filter(f=>f.endsWith('.ts')||f.endsWith('.tsx'));
  // Graph summary
  const gj=execSync('cd '+ROOT+' && bun scripts/graph.ts --json 2>/dev/null',{encoding:'utf8',timeout:12000});
  const g=JSON.parse(gj);
  const inDeg=new Map();
  g.edges.forEach(e=>inDeg.set(e.target,(inDeg.get(e.target)||0)+1));
  const byId=new Map(g.nodes.map(n=>[n.id,n]));
  const top=[...inDeg.entries()].sort((a,b)=>b[1]-a[1]).slice(0,10).map(([id,n])=>{const nd=byId.get(id);return nd?n+'x '+nd.label:''}).filter(Boolean);
  const lines=['=== CODEBASE: '+g.nodes.length+' nodes '+g.edges.length+' edges ==='];
  if(changed.length)lines.push('CHANGED: '+changed.join(', '));
  lines.push('TOP IMPORTED: '+top.join(' | '));
  lines.push('QUERY: bun scripts/graph.ts --focus <path> --json');
  console.log(lines.join('\n'));
}catch(e){console.log('graph: unavailable');}
"
